settings.upgradesection-content:
{% if product.metafields.custom.upgrade_display_hide != false %}
<style>
    .upgrade-box-top {
  margin: -35px 20px 0;
  text-align: left;
}
.upgrade-box-bottom {
    display: flex;
    align-items: center;
    gap: 10px;
}
li {
    padding-bottom: 8px;
}
  i.uil.uil-check {
    background: #00b67a;
    width: 18px;
    height: 18px;
    border-radius: 100%;
    display: inline-block;
    color: #fff;
    text-align: center;
    font-size: 14px;
}
.badge {
    background-color: #fff;
    color: #58327a;
    padding: 4px 16px;
    border: 2px solid #58327a;
    border-radius: 50px;
    cursor: pointer;
    display: inline-block;
    font-size: 16px;
    font-weight: bold;
    margin-bottom: 8px;
}
.content-right{
    display: flex;
}
.heading {
  font-size: 20px;
  font-weight: 600;
  margin: 12px 0 0;
}
.text {
    margin-bottom: 20px;
   padding-right: 5px;
  width: max-content;
}

 .upgrade-section img {
  width: 160px;
  height: auto;

}
.bullets {
    list-style-type: none;
    padding: 0;
    font-size: 16px;
}
.content-left {
  text-align: left;
}
.bullets li i {
  margin-right: 5px; 
}
.cta-button {
    color: #58327a;
    cursor: pointer;
    font-size: 16px;
    border-bottom: 1.5px solid #58327a;
    padding-bottom: 0px;
    display: inline;
    font-weight:bold;
}
@media (max-width: 420px) {
 .upgrade-section img {
          width: 100px; 
          height: 120px; 
      }
      .upgrade-box-top {
          margin: -38px 0 0 5px; 
      }
      .badge {
          padding: 8px 15px; 
      }
      .heading {
          font-size: 20px; 
      }
      .text {
         margin-bottom: 20px;
      }
      .bullets {
          font-size: 14px; 
      }
  }
</style>
<a href="{{ product.metafields.custom.upgrade_cta_link}}">
<div class="upgrade-box">
    <div class="upgrade-box-top">
  {% if product.metafields.custom.upgrade_badge %}
      <div class="badge">{{ product.metafields.custom.upgrade_badge }}</div>
  {% endif %}
</div>

    <div class="upgrade-box-bottom">
       {% if product.metafields.custom.upgrade_image != blank %}
      <div class="content-right">
        <img src="{{ product.metafields.custom.upgrade_image | img_url: 'medium' }}" alt="">
      </div>
    {% endif %}    
        <div class="content-left">
            <div class="heading">{{ product.metafields.custom.upgrade_title }}</div>
            <div class="text">
              <ul class="bullets">
                  {% if product.metafields.custom.upgrade_checklist_1 %}
                      <li><i class="uil uil-check"></i>{{ product.metafields.custom.upgrade_checklist_1 }}</li>
                  {% endif %}
                  {% if product.metafields.custom.upgrade_checklist_2 %}
                      <li><i class="uil uil-check"></i>{{ product.metafields.custom.upgrade_checklist_2 }}</li>
                  {% endif %}
                  {% if product.metafields.custom.upgrade_checklist_3 %}
                      <li><i class="uil uil-check"></i>{{ product.metafields.custom.upgrade_checklist_3 }}</li>
                  {% endif %}
              </ul>
          </div>
            <p class="cta-button">{{ product.metafields.custom.upgrade_cta_text }}</p>
        </div>
    </div>
</div>
</a>
{% endif %}

